SELECT INSR_PROD_CD AS insrProdCd, INSR_PROD_NM AS insrProdNm, SOC AS soc, MONTHLY_FEE AS monthlyFee, JOIN_TYPE AS joinType, REQ_BUY_TYPE AS reqBuyType, CLAUSE_URL AS clauseUrl, USE_YN AS useYn, SORT_SEQ AS sortSeq FROM MSF_INSR_PROD WHERE USE_YN = 'Y'
AND REQ_BUY_TYPE = #{reqBuyType}
ORDER BY SORT_SEQ
